import{_ as a,o as i,c as l,ai as n}from"./chunks/framework.Dazo0ijd.js";const g=JSON.parse('{"title":"大模型应用","description":"","frontmatter":{"title":"大模型应用","order":30},"headers":[],"relativePath":"ai/app/index.md","filePath":"ai/app/index.md"}'),t={name:"ai/app/index.md"};function r(p,e,o,c,s,d){return i(),l("div",null,[...e[0]||(e[0]=[n('<h1 id="大模型应用开发技术" tabindex="-1">大模型应用开发技术 <a class="header-anchor" href="#大模型应用开发技术" aria-label="Permalink to “大模型应用开发技术”">​</a></h1><p>大模型应用开发基于已有的 C/S 架构的<a href="/client/">客户端</a>和<a href="/server/">服务端</a>技术栈，在前后端分别引入新的组件，推动大模型的能力落地到实际的生产环节中。</p><ul><li>2022 年 10 月，GPT 横空出世</li><li>2023 年，各大互联网公司纷纷下场，开启大模型竞赛，推出各家的聊天模型</li><li>2024 年，RAG 技术和联网搜索逐步成形，大模型的幻觉问题得到初步解决</li><li>2025 年，智能体技术提出，模型不只要能回答，更要能动手做</li><li>2026 年，大模型应用理论体系已经初具体系之态</li></ul><p>短短 3 年，AI 大模型应用技术以野蛮姿态生长，新技术层出不穷，不断加入到已有的技术体系中，逐步形成了一个完整的结构体系。</p><h2 id="新组件" tabindex="-1">新组件 <a class="header-anchor" href="#新组件" aria-label="Permalink to “新组件”">​</a></h2><p>大模型应用在传统 Web 架构的基础上引入了三个新角色，它们分别对应模型服务、知识检索和自主行动三个核心能力。</p><p>模型推理引擎负责将大模型作为服务暴露给上层应用。vLLM 是目前最主流的选择，它基于 PagedAttention 算法管理 KV Cache 显存，将显存利用率从 20-30% 提升到接近 80%，且完全兼容 OpenAI API 协议，可以无缝替换 OpenAI 端点。其他值得关注的引擎包括 SGLang（前缀缓存和结构化生成方面有创新）、llama.cpp（专注于消费级硬件上的量化推理）、TGI（HuggingFace 官方方案，生态集成好）。推理引擎的选型考量因素包括：支持的最大上下文长度、连续批处理能力（Continuous Batching）、量化方案（AWQ/GPTQ/FP8）、投机解码（Speculative Decoding）加速等。</p><p>向量数据库是 RAG 架构的核心基础设施，Milvus 是其中的代表性产品。它提供毫秒级的十亿级向量检索能力，支持 HNSW、IVF、DiskANN 等多种索引类型，原生支持分布式部署和流批一体写入。除 Milvus 外，Qdrant、Weaviate、pgvector 等方案各有侧重——pgvector 的 PostgreSQL 原生集成使其在已有 PG 基础设施的团队中部署成本极低。向量库的选型需要综合考虑索引算法与硬件资源的匹配、分布式扩展的复杂度、以及过滤查询（标量 + 向量的混合搜索，即 Hybrid Search）的效率。</p><p>Agent 智能体将大模型从&quot;问答机&quot;升级为&quot;行动者&quot;。它赋予模型调用外部工具（Function Calling）、规划任务步骤（Plan &amp; Execute）、维护对话状态（Session Management）的能力。Agent 的核心技术组件包括工具定义与调用协议（JSON Schema → 外部 API 的桥接）、记忆系统（短期对话记忆 + 长期知识记忆）、以及安全护栏（防止越权操作、注入攻击、无意义循环）。Agent 框架的选择——LangGraph（有状态工作流编排）、CrewAI（多 Agent 角色协作）、AutoGen（微软的多 Agent 对话框架）——取决于业务场景的复杂度。</p><p>这三个新组件并非独立运行，它们在架构的多个层面与传统技术栈交织：推理引擎与 GPU 硬件和模型训练链路对接，向量数据库与数据工程和 Embedding 模型对接，Agent 与会话管理和前端 UI 对接。理解这些组件的技术原理和工程边界，是构建生产级大模型应用的前提。</p><h2 id="内容结构" tabindex="-1">内容结构 <a class="header-anchor" href="#内容结构" aria-label="Permalink to “内容结构”">​</a></h2><p>大模型应用开发的知识体系按层级组织：</p><ul><li>架构层（arch）：API 设计、模型网关、智能路由、AI Native 架构模式</li><li>推理引擎层（engine）：vLLM、Ollama、量化推理、垂直领域微调、LLMOps</li><li>框架库层（lib）：LangChain、LlamaIndex 等开发框架的工程化使用</li><li>覆盖层（overlay）：叠加在前后端基础技术栈之上的 AI 处理层 <ul><li>Agent：工具调用、ReAct 循环、MCP 协议、A2A 协议、Deep Agent</li><li>RAG：Embedding、向量检索、GraphRAG、数据工程、Agentic RAG</li><li>Session：提示词工程、上下文管理、会话记忆</li><li>Ops：评估框架、可观测性工具、A/B 测试</li><li>UI：流式渲染、生成式 UI、结构化输出、浏览器端推理</li></ul></li></ul>',13)])])}const h=a(t,[["render",r]]);export{g as __pageData,h as default};
